import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, CircularProgress } from '@mui/material';
import response from './response.json';

interface TripData {
  upcomingTrip: {
    destination: string;
    departureDate: string;
    countdownDays: number;
  };
  packingProgress: {
    totalItems: number;
    packedItems: number;
    packingPercentage: number;
  };
  checklist: {
    item: string;
    status: string;
  }[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const tripData = response.data as TripData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#121212' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor, mb: 1 }}>
              Upcoming Trip
            </Typography>
            <Typography variant="body2" sx={{ color: '#E0E0E0' }}>
              Destination: {tripData.upcomingTrip.destination}
            </Typography>
            <Typography variant="body2" sx={{ color: '#E0E0E0', mt: 0.5 }}>
              Departure Date: {tripData.upcomingTrip.departureDate}
            </Typography>
            <Typography variant="body2" sx={{ color: '#E0E0E0', mt: 0.5 }}>
              Countdown: {tripData.upcomingTrip.countdownDays} days
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#E0E0E0', mb: 0.5 }}>
              Packing Progress
            </Typography>
            <CircularProgress
              variant="determinate"
              value={tripData.packingProgress.packingPercentage}
              sx={{ color: metaData.accentColor, mb: 1 }}
            />
            <Typography variant="caption" sx={{ color: '#E0E0E0' }}>
              {tripData.packingProgress.packedItems} of {tripData.packingProgress.totalItems} items packed
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#E0E0E0', mb: 0.5 }}>
              Checklist
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {tripData.checklist.slice(0, 3).map((item, index) => (
                <Chip
                  key={index}
                  label={item.item}
                  sx={{
                    fontSize: '11px',
                    px: 1,
                    py: 0.5,
                    bgcolor: item.status === 'completed' ? metaData.primaryColor : '#424242',
                    color: '#FFFFFF',
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
